window.__QUIZ_DATA__=[{"id":"objective>Geography>1995>1","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of DOBA DISTRICT to answer the question      The scale of the map is","images":["data:image/png;base64,"],"options":{"A":"1:2,000","B":"1:5,000","C":"1:50,000","D":"1:100,000"},"answer":"C","explanation":"The distance from 0 to 1 on the map scale using ruler is 2cm and the distance on the ground from the scale is 1km. Therefore, the statement scale= 2cm to 1km and 1:50,000 in representative fraction","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>2","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of DOBA DISTRICT to answer the question    The feature running north-south in the central part of the map is best described as a","images":["data:image/png;base64,"],"options":{"A":"conical hill","B":"pyramidal peak","C":"knoll","D":"ridge"},"answer":"D","explanation":"The feature running north-south in the central part of the map is best described as a ridge.A ridge is a strip of highland which is narrow and elongated. The contours run almost parallel","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>3","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of DOBA DISTRICT to answer the question    The angular bearing of Baku from Ase is approxmately","images":["data:image/png;base64,"],"options":{"A":"045o","B":"060o","C":"135o","D":"315o"},"answer":"D","explanation":"The angular bearing of Baku from Ase is approxmately 315o","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>4","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of DOBA DISTRICT to answer the question    The feature marked X is best described as a","images":["data:image/png;base64,"],"options":{"A":"pass","B":"depression","C":"spur","D":"valley"},"answer":"A","explanation":"The feature marked X is best described as a pass. A pass is a stretch of lowland which seperates two highlands but at lower levels","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>5","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of DOBA DISTRICT to answer the question    The distance from Baku to Ibaga along the secondary road is","images":["data:image/png;base64,"],"options":{"A":"2.4 km","B":"4.8 km","C":"9.6 km","D":"10.5 km"},"answer":"C","explanation":"By using a piece of thread, the distance from Baku to Ibaga along the secondary road is 9.6 km. Since the scale of the map is 2cm to 1km, 9.6cm implies 4.8km on the ground.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>6","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of DOBA DISTRICT to answer the question    The drainage pattern on the map is","images":["data:image/png;base64,"],"options":{"A":"antecedent","B":"consequent","C":"dendritic","D":"radial"},"answer":"D","explanation":"According to the map, the drainage pattern on the map is radial . It is seen that many rivers, strams or their tributaries diverge from a central elevated highland and flow away to different directions.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>7","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of DOBA DISTRICT to answer the question    The direction of flow of River Bidol is","images":["data:image/png;base64,"],"options":{"A":"south-eastwards.","B":"northwards","C":"westwards","D":"north-eastwards"},"answer":"D","explanation":"River Bidol flows through the north-eastern direction.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>8","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of DOBA DISTRICT to answer the question    Which of the following statements about the communication network on the map is correct? The routes","images":["data:image/png;base64,"],"options":{"A":"link mineral producing areas","B":"run from north to south","C":"take advantage of low relief","D":"are predominant in the north"},"answer":"C","explanation":"On the map, the communication network take advantage of low relief","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>9","subject":"Geography","year":"1995","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Use the map of DOBA DISTRICT to answer the question    Which of the following settlements is linear?","images":["data:image/png;base64,"],"options":{"A":"Baku","B":"Ase","C":"Chonda","D":"Doba"},"answer":"D","explanation":"Doba is a linear settlement. In a linear settlement, buildings are located along the roads, railways or even rivers in a linear form.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>10","subject":"Geography","year":"1995","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Use the map of DOBA DISTRICT to answer the question    A crop likely to be produced in the lower valley of River Bidol is","images":["data:image/png;base64,"],"options":{"A":"wheat","B":"rubber","C":"rice","D":"yam"},"answer":"C","explanation":"The lower valley of River Bidol is poorly drained and is liable to flooding. Rice is likely to be produced in such a marshy area.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>11","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The satellite of the earth is","images":[],"options":{"A":"the sun","B":"Jupiter","C":"the moon","D":"Saturn"},"answer":"C","explanation":"The satellite of the Earth is the Moon. A satellite is a celestial body that orbits around a planet. In this case, the Moon orbits around the Earth, making it the Earth's satellite.","marks":"1","difficulty":"1"},{"id":"objective>Geography>1995>12","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The commentary of a football match which started at 1600 hours GMT in a town P (450W) was heard in town Q at 2200 hours GMT. What is the longitude of Q","images":[],"options":{"A":"39oW","B":"45oE","C":"51oE","D":"135oW"},"answer":"D","explanation":"Town P(45oW)--16:00 \u2190Add| Town Q?E --22:00  Time of Town P has to come first before Town Q because 1600hours comes before 2200 hours the same day.  Time difference= 22:00 - 16:00 = 6 hours.  Recall:   15o=1hour  x=6hrs  x=90o.  Since the arrow is not pointing to the question mark; we add 90o to 45o. 90o + 45o=135oE","marks":"1","difficulty":"3"},{"id":"objective>Geography>1995>13","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following statements about Jupiter is not true? It","images":[],"options":{"A":"is the next planet to the Earth","B":"revolves round the sun","C":"is the only planent with twelves satellites","D":"is the largest planent jin the solar system"},"answer":"A","explanation":"The statement that Jupiter is the next planet to the Earth is not true. In the solar system, the order of the planets from the sun is Mercury, Venus, Earth, Mars, Jupiter, Saturn, Uranus, and Neptune. Therefore, Mars is the next planet to the Earth, not Jupiter.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>14","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Igneous rocks contain","images":[],"options":{"A":"humus","B":"fossils","C":"strata","D":"crystals"},"answer":"D","explanation":"Igneous rocks are crystalline i.e they contain crystals. They are non stratified rock andthey do not contain fossils.","marks":"1","difficulty":"1"},{"id":"objective>Geography>1995>15","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"An active volcano is one that","images":[],"options":{"A":"has not erupted recently","B":"will not erupt","C":"had earlier erupted violently","D":"erupts periodically"},"answer":"D","explanation":"An active volcano is one that erupts periodically. It is known for its frequent eruption, especially in its early stage.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>16","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"The principal agents in soil erosion are","images":[],"options":{"A":"wind and waves","B":"water and wind","C":"air and water","D":"water and dust"},"answer":"B","explanation":"The principal agents in soil erosion are water and wind. These natural forces carry away the topsoil, which is rich in nutrients, and deposit it elsewhere. This process is known as erosion. The other options are incorrect because waves, air, and dust are not the principal agents of soil erosion.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>17","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Soil erosion leads to all the following except the","images":[],"options":{"A":"loss of available plant nutrients","B":"loss of cultivable land","C":"loss of water reservoirs such as dams","D":"increase in yield per hectare"},"answer":"D","explanation":"Soil erosion does not leads to an increase in yield per hectare, rather, it reduces yield per hectare","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>18","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The term watershed refers to the","images":[],"options":{"A":"direction of flow of a river from its source to the sea","B":"volume of load carried by a river","C":"crestlines from which two or more rivers flow in opposite directions","D":"area drained by the main river and all its tributaries"},"answer":"C","explanation":"A watershed refers to the highland area which separates two or more  rivers or two river basins. It is the crestlines from which two or more rivers flow in opposite directions.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>19","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"A spring is an outlet for","images":[],"options":{"A":"rivers","B":"streams in Karst regions","C":"underground water","D":"rain water in limestone regions"},"answer":"C","explanation":"A spring is a major feature of underground water. It is a natural flow of water from underground to the surface of the earth.","marks":"1","difficulty":"1"},{"id":"objective>Geography>1995>20","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following represents the correct sequence in which denudation occurs?","images":[],"options":{"A":"Weathering.....Erosion......Deposition","B":"Deposition....Weathering....Erosion","C":"Erosion....Weathering......Deposition","D":"Weathering...Deposition...Erosion"},"answer":"A","explanation":"The correct sequence in which denudation occurs Weathering.....Erosion.....transportation.....Deposition","marks":"1","difficulty":"3"},{"id":"objective>Geography>1995>21","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following is a features of erosion in arid regions?","images":[],"options":{"A":"Caldera","B":"Barchan","C":"Yardang","D":"Pediment"},"answer":"C","explanation":"Yardangs are features of wind erosion in arid regions(desert). Yardangs are formed when hard and soft rocks in vertical bands are aligned in the direction of prevailing winds. Wind abrasion wears the softer rocks into long narrow corridors which separate the steep-sided ridges of the hard rocks. These hard rocks are called Yardangs","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>22","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The water in which is thrown against the beach by a breaking wave is called","images":[],"options":{"A":"an undertow","B":"a backwash","C":"a fetch","D":"a swash"},"answer":"D","explanation":"Swash refers to the turbulent layer of water that washes up on the beach after an incoming wave has broken.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>23","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following feature is not associated with coastal erosion?","images":[],"options":{"A":"Wave-cut platform","B":"Stack","C":"Geo","D":"Bay"},"answer":"D","explanation":"Capes and bays, cliffs,coastal cave, arch, stack, stump, geo and gloup are all features associated with coastal erosion. Marine dune is  not a feature associated with coastal erosion.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>24","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"A slender, downward growing pinnacle that hangs from a cave roof is a","images":[],"options":{"A":"stalagmite","B":"grike","C":"stalactite","D":"clint"},"answer":"C","explanation":"A stalactite is an underground feature of limestone region. They are found in caves and they grow from up, downwards and may join stalagmite to form pillars.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>25","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Lacustrine plains are formed","images":[],"options":{"A":"on the bed of an old lake","B":"at the foot of a mountain","C":"in a rift valley","D":"on top of a plateau"},"answer":"A","explanation":"A Lacustrine plain or lake plain is a plane formed due to the past existence of a lake and its accompanying sediment accumulation.  Lacustrine plains are formed on the bed of an old lake","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>26","subject":"Geography","year":"1995","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"All the following are ways in which rivers are useful to man except the","images":[],"options":{"A":"formation of political boundaries between countries","B":"provision of rich agricultural land","C":"generation of hydro-electricity","D":"relocation of settlement after flooding"},"answer":"D","explanation":"Rivers are indeed useful to man in many ways such as forming political boundaries between countries, providing rich agricultural land, and generating hydro-electricity. However, the relocation of settlement after flooding is not a way in which rivers are useful. Instead, it is a consequence of a natural disaster that forces people to move and resettle.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1995>27","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following is not a characteristic of the tropical desert climate?","images":[],"options":{"A":"Low humidity","B":"Cloudless skies","C":"Dust haze","D":"Very low annual range of temperature"},"answer":"D","explanation":"The tropical desert climate is characterized by low humidity, cloudless skies, and dust haze. However, it also has a very high annual range of temperature, not a very low one. This is because deserts can be extremely hot during the day and very cold at night.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>28","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following factors is least important in determining the temperature of a place?","images":[],"options":{"A":"angle at which the sun's rays strike the earth's surface.","B":"rate of transpiration","C":"number of hours of sunshine","D":"altitude above sea level."},"answer":"B","explanation":"Latitude, distance from sea, cloud cover and humidity,altitude, length of day and ocean currents are all major factors on which temperature of a place depends on. The rate of transpiration is least important","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>29","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The ancient Greeks classified the climates of the world into","images":[],"options":{"A":"torrid, temperate and frigid zones","B":"hot, cold and medium zones","C":"torrid, equatorial and polar zones","D":"hot, mild and cool zones"},"answer":"A","explanation":"The ancient Greeks classified the climates of the world into three zones: torrid, temperate and frigid. The torrid zone is the area near the equator and is characterized by high temperatures. The temperate zones are in the middle latitudes between the torrid zone and the frigid zones, and have moderate temperatures. The frigid zones are near the poles and are characterized by very cold temperatures.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>30","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"The tropical rainforest is characterized by all the following except","images":[],"options":{"A":"a distinct layered arrangement.","B":"multiple plant species","C":"evergreen trees","D":"trees with thorny leaves"},"answer":"D","explanation":"The tropical rainforest is characterized by a distinct layered arrangement, multiple plant species, and evergreen trees. However, trees with thorny leaves are not a characteristic of the tropical rainforest. Thorny leaves are more common in desert or arid environments, where plants have evolved thorns as a defense mechanism to prevent water loss.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>31","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Oak and cedar are good examples of commercial trees common in the","images":[],"options":{"A":"equatorial vegetation","B":"Mediterranean vegetation","C":"Monsoon Vegetation","D":"Tundra Vegetation"},"answer":"B","explanation":"In the Mediterranean vegetation, the plant communities are evergreen wood plants such as oak, wild olive, cypress etc., evergreen coniferous tree such as cedars, pines etc and Mediterranean bushes and shrubs such as acacia,laurel,rosemary etc.","marks":"1","difficulty":"1"},{"id":"objective>Geography>1995>32","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"The effect of humus in the soil is make the soil","images":[],"options":{"A":"retain more air","B":"retain more moisture","C":"sparkle","D":"very soft"},"answer":"B","explanation":"Humus is the organic component of soil, formed by the decomposition of leaves and other plant material by soil microorganisms. It helps the soil retain more moisture. This is because humus particles have many charged sites that attract and hold onto water. This property also allows humus to hold onto nutrients and release them slowly to plants.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>33","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Local farmers determine the change in fertility of any tropical soil through the","images":[],"options":{"A":"nature of the surface","B":"amount of water in the soil","C":"variation in yeld from crops growth","D":"colour of the soil"},"answer":"D","explanation":"Through the colour of the soil, local farmers determine the change in fertility of any tropical soil","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>34","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Heavy rainfall favours the formation of acid soils because it","images":[],"options":{"A":"results in capillary rise of base elements from deep below","B":"results in greater weatering of minerals","C":"causes more leaching of base elements","D":"result in capillary rise of base elements from deep below"},"answer":"C","explanation":"Heavy rainfall favours the formation of acid soils because it causes more leaching of base elements. Leaching is the process by which soluble substances are washed out of soil or wastes. These leached out nutrients are then carried downward through the soil and can be deposited in a lower layer, or perhaps even washed out of the soil altogether. This process can lead to the formation of acid soils, as the removal of base elements such as calcium, magnesium, potassium and sodium can result in a soil with a low pH, which is characteristic of acid soils.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1995>35","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"The relationship between organisms in the ecosystem implies that the components","images":[],"options":{"A":"are Interdependent","B":"share common ideas","C":"give birth to one another","D":"are enemies"},"answer":"A","explanation":"The relationship between the components of the ecosystem can best be described as interdependent. In other words, all the components in an ecosystem depend on one another and they cannot exist in isolation","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>36","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"All the following are major pollutants of the environment except","images":[],"options":{"A":"the flaring of gas in oil wells","B":"oil spillage","C":"industrial waste products","D":"domestic cooking"},"answer":"D","explanation":"Domestic cooking is not considered a major pollutant of the environment. While it can contribute to indoor air pollution if not properly ventilated, it does not have the same large-scale impact on the environment as the flaring of gas in oil wells, oil spillage, or industrial waste products. These activities release harmful substances into the environment, causing pollution.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>37","subject":"Geography","year":"1995","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Settlements can be classified according to all the following except","images":[],"options":{"A":"arrangement of the buildings","B":"number of people per settlement","C":"main occupation of the inhabitants","D":"number of buildings per unit area and land"},"answer":"C","explanation":"Settlements are primarily classified according to their pattern, size, housing density and the type of people that live in the area. Settlements are not classified  based on the main occupation of the inhabitants.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>38","subject":"Geography","year":"1995","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"When two separate towns grow and merge into, the one new settlement formed is called a","images":[],"options":{"A":"conurbation","B":"megalopoils","C":"dormitory town","D":"metropolis"},"answer":"A","explanation":"A conurbation is made up of several towns joined together but, each town still maintains its identity","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>39","subject":"Geography","year":"1995","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"All the following are examples of heavy industries except","images":[],"options":{"A":"furniture making","B":"ship building","C":"refining of petroleum","D":"iron and steel"},"answer":"A","explanation":"ship building, refining of petroleum, iron and steel and aluminium smelting are all heavy industries. Furniture making falls under the light industries which produce relatively light weight goods.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>40","subject":"Geography","year":"1995","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"Which of the following is not a major problem of economic development in developing countries? Inadequate","images":[],"options":{"A":"capital","B":"natural resources","C":"technical know-how","D":"transportation facilities"},"answer":"B","explanation":"Most developing countries possess adequate natural resources. Natural resources is not a major problem of economic development in developing countries.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1995>41","subject":"Geography","year":"1995","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Jos has a heavier rainfall than the other towns on the same latitude in Nigeria because it","images":[],"options":{"A":"has lower temperatures","B":"is located on the windward side of a pleteau","C":"is located near the coast","D":"is located on the path od descending winds"},"answer":"B","explanation":"Jos is located on the windward side of a pleteau which makes it have a heavier rainfall than the other towns.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>42","subject":"Geography","year":"1995","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"The important area for lumbering in Nigeria is found in the","images":[],"options":{"A":"Benin-Obudu-Yola region","B":"Ibadan-Benin-Port Harcourt region","C":"Lagos-Port Harcourt-Calabar region","D":"Minna-Lokoja-Makurdi region"},"answer":"B","explanation":"The most important area for lumbering in Nigeria is found in the Ibadan-Benin-Port Harcourt region","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>43","subject":"Geography","year":"1995","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"Jebba, Lokoja and Onitsha are examples of","images":[],"options":{"A":"packet stations","B":"railway stations","C":"sea ports","D":"river ports"},"answer":"D","explanation":"Examples of river ports are:  Jebba port (Kwara state)  Lokoja port (kogi state)   -Onitsha port (Anambra state)","marks":"1","difficulty":"1"},{"id":"objective>Geography>1995>44","subject":"Geography","year":"1995","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Which of the following is true of manufacturing industries in Nigeria?","images":[],"options":{"A":"Most of them produce consumer goods.","B":"Large quantities of their products are exported","C":"They depend totally on local raw materials.","D":"They were established in pre-colonial times."},"answer":"A","explanation":"One of the characteristics of manufacturing industries in Nigeria is the production of consumer goods","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>45","subject":"Geography","year":"1995","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"The low level of economic development of the Eastern Scarplands of Nigeria is due to its","images":[],"options":{"A":"rugged topography","B":"overpopulation","C":"high temperature","D":"thick vegetation"},"answer":"A","explanation":"The Eastern Scarplands of Nigeria has a rugged topography which results in its low level of development.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1995>46","subject":"Geography","year":"1995","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : SETTLEMENT","question":"Which of the following is the characteristic pattern of rural settlements in the Western Highlands of Nigeria?","images":[],"options":{"A":"Linear","B":"Dispersed","C":"Satellite","D":"Nucleated"},"answer":"D","explanation":"In the Western Highlands of Nigeria, the Yoruba people are the major ethnic group in this region. They have nucleated settlements.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>47","subject":"Geography","year":"1995","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Africa is threatened today by serious soil erosion because the","images":[],"options":{"A":"soils are porous","B":"landscape is characterised by mountains.","C":"rainfall is heavy all over Africa.","D":"soils are recklessly exposed"},"answer":"D","explanation":"Soil erosion in Africa is a serious issue primarily due to reckless exposure of soils. This is often due to deforestation, overgrazing, and unsustainable farming practices that leave the soil exposed to wind and water erosion.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>48","subject":"Geography","year":"1995","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"The largest irrigation scheme in Africa is served by the","images":[],"options":{"A":"Sennar Dam","B":"Kainji Dam","C":"Akosombo Dam","D":"Tiga Dam"},"answer":"A","explanation":"Sudan has the largest irrigation scheme in Africa, Gezira irrigation scheme in Al Jazirah. It is served by the Sennar Dam in Sudan.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>49","subject":"Geography","year":"1995","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Which of the following vegetation belts in Africa is usually associated with the tropical continental climate?","images":[],"options":{"A":"Tropical desert","B":"Sudan Savanna","C":"Guinea Savanna","D":"Tropical rainforest"},"answer":"B","explanation":"The Sudan Savanna vegetation belt in Africa is usually associated with the tropical continental climate. This climate is characterized by high temperatures throughout the year and a seasonal rainfall pattern. The vegetation in this region is adapted to these conditions and includes a mix of grasses and trees.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1995>50","subject":"Geography","year":"1995","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Which of the following lakes is not found in the East African Rift Valley?","images":[],"options":{"A":"Lake Turkana","B":"Lake Tanganyika","C":"Lake Mweru","D":"Lake Tana."},"answer":"D","explanation":"Lake Tanganyika, lake Victoria, lake Turkana, Lake Mweru  and Lake Tana are all lakes found in the East African Rift Valley. Lake Mobutu is found in the Western Rift Valley in east-central Africa.","marks":"1","difficulty":"2"}];